import { createContext } from 'react';

export interface PopupsContextData {
	applicationElementID?: string;
	rootElement?: HTMLElement | ShadowRoot | null;
}

/**
 * Переопределяет идентификатор контейнера куда будет отображаться содержимое всех компонентов созданных через createPortal
 */
const defaultContextValue: PopupsContextData = {
	applicationElementID: 'root',
	rootElement: undefined,
};

export const PopupsContext = createContext<PopupsContextData>(defaultContextValue);
